mapper.select:
SELECT  
  FROM  TB_BATCH_RESULT A
 WHERE  A.BATCH_RESULT_ID = #{batchResultId}

mapper.insert:
INSERT  INTO TB_BATCH_RESULT
      ( BATCH_RESULT_ID
      , BATCH_SCHDUL_ID
      , BATCH_OPERT_ID
      , PARAMTR
      , STTUS
      , ERROR_INFO
      , EXECUT_BEGIN_TM
      , EXECUT_END_TM
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{batchResultId}
        , #{batchSchdulId}
        , #{batchOpertId}
        , #{paramtr}
        , #{sttus}
        , #{errorInfo}
        , #{executBeginTime}
        , #{executEndTime}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )
